    private string _fontClass => FontSize.ToLowerInvariant() switch
    {
        "small" => "preview-font-small",
        "large" => "preview-font-large",
        _ => "preview-font-medium"
    };

    private bool _compactMode => CompactMode;
}

@namespace sv_727400e45d114820a815880ed7ca91b9.Components.Settings
@using sv_727400e45d114820a815880ed7ca91b9.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Appearance Settings</h2>

    @if (_loading)
    {
        <p>Loading appearance settings...</p>
    }
    else
    {
        <div class="appearance-form">
            <div class="form-group">
                <label>Theme</label>
                <div class="radio-group">
                    @foreach (var theme in _themes)
                    {
                        <label class="radio-item">
                            <input type="radio" name="theme" value="@theme"
