@namespace sv_727400e45d114820a815880ed7ca91b9.Components.Settings
@using sv_727400e45d114820a815880ed7ca91b9.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Profile Settings</h2>

    @if (_loading)
    {
        <p>Loading profile...</p>
    }
    else
    {
        <div class="profile-form">
            <div class="avatar-preview">
                <img src="@_avatarUrl" alt="Avatar" class="avatar-image" />
                <p class="avatar-url-display">@_avatarUrl</p>
            </div>

            <div class="form-group">
                <label for="displayName">Display Name</label>
                <input id="displayName" type="text" @bind="_displayName" class="form-control" />
            </div>

            <div class="form-group">
                <label for="email">Email</label>
                <input id="email" type="email" @bind="_email" class="form-control" />
            </div>

            <div class="form-group">
                <label for="bio">Bio</label>
                <textarea id="bio" @bind="_bio" class="form-control" rows="4"></textarea>
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveChanges">Save Changes</button>
                <button class="btn btn-secondary" @onclick="DiscardChanges">Discard Changes</button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast toast-success">Profile saved successfully!</div>
            }
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _showSuccess;

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";

    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfile();
    }

    private async Task LoadProfile()
    {
        _loading = true;
        _savedProfile = await SettingsService.GetProfileAsync();
        ApplyProfile(_savedProfile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _avatarUrl = profile.AvatarUrl;
        _bio = profile.Bio;
    }

    private async Task SaveChanges()
    {
        var updatedProfile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(updatedProfile);
        _savedProfile = updatedProfile;
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }

    private void DiscardChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
    }
}

@namespace sv_727400e45d114820a815880ed7ca91b9.Components.Settings
@using sv_727400e45d114820a815880ed7ca91b9.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Notification Preferences</h2>

    @if (_loading)
    {
        <p>Loading notification preferences...</p>
    }
    else
    {
        <div class="notifications-form">
            <div class="toggle-group">
                <label class="toggle-item">
                    <input type="checkbox" @bind="_emailNotifications" class="toggle-switch" />
                    <span>Email Notifications</span>
                </label>

                <label class="toggle-item">
                    <input type="checkbox" @bind="_pushNotifications" class="toggle-switch" />
                    <span>Push Notifications</span>
                </label>

                <label class="toggle-item">
                    <input type="checkbox" @bind="_weeklyDigest" class="toggle-switch" />
                    <span>Weekly Digest</span>
                </label>
            </div>

            <div class="channels-section">
                <h3>Muted Channels</h3>
                @foreach (var channel in _channels)
                {
                    <label class="channel-item">
                        <input type="checkbox"
                               checked="@_mutedChannels.Contains(channel)"
                               @onchange="e => ToggleChannel(channel, (bool)e.Value!)" />
                        <span>@channel</span>
                    </label>
                }
            </div>

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SavePreferences">Save Preferences</button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast toast-success">Preferences saved successfully!</div>
            }
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _showSuccess;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = new();
    private List<string> _channels = new() { "general", "announcements", "random", "engineering", "design", "marketing" };

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _mutedChannels = new HashSet<string>(prefs.MutedChannels);
        _loading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SavePreferences()
    {
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, _mutedChannels.ToList());
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

@namespace sv_727400e45d114820a815880ed7ca91b9.Components.Settings
@using sv_727400e45d114820a815880ed7ca91b9.Models
@inject ISettingsService SettingsService

<div class="expandable-panel">
    <button class="panel-header" @onclick="() => _expanded = !_expanded">
        <span>Change Password</span>
        <span class="panel-toggle">@(_expanded ? "▲" : "▼")</span>
    </button>

    @if (_expanded)
    {
        <div class="panel-body">
            <div class="form-group">
                <label for="currentPassword">Current Password</label>
                <input id="currentPassword" type="password" @bind="_currentPassword" class="form-control" />
            </div>

            <div class="form-group">
                <label for="newPassword">New Password</label>
                <input id="newPassword" type="password" @bind="_newPassword" class="form-control" />
            </div>

            <div class="form-group">
                <label for="confirmPassword">Confirm Password</label>
                <input id="confirmPassword" type="password" @bind="_confirmPassword" class="form-control" />
            </div>

            @if (!string.IsNullOrEmpty(_error))
            {
                <div class="toast toast-error">@_error</div>
            }

            @if (_showSuccess)
            {
                <div class="toast toast-success">Password updated successfully!</div>
            }

            <button class="btn btn-primary" @onclick="UpdatePassword" disabled="@_updating">
                @(_updating ? "Updating..." : "Update Password")
            </button>
        </div>
    }
</div>

@code {
    private bool _expanded;
    private bool _updating;
    private bool _showSuccess;
    private string _error = "";
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";

    private async Task UpdatePassword()
    {
        _error = "";
        _showSuccess = false;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _error = "All password fields are required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _error = "New password and confirmation do not match.";
            return;
        }

        _updating = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _showSuccess = true;
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _ = HideSuccessAfterDelay();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _updating = false;
        }
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

@namespace sv_727400e45d114820a815880ed7ca91b9.Components.Settings
@using sv_727400e45d114820a815880ed7ca91b9.Models
@inject ISettingsService SettingsService

<div class="sessions-section">
    <h3>Active Sessions</h3>

    <table class="sessions-table">
        <thead>
            <tr>
                <th>Device</th>
                <th>Location</th>
                <th>Last Active</th>
                <th>Action</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var session in Sessions)
            {
                <tr>
                    <td>@session.Device</td>
                    <td>@session.Location</td>
                    <td>@session.LastActive.ToString("g")</td>
                    <td>
                        @if (session.Id != CurrentSessionId)
                        {
                            <button class="btn btn-danger btn-sm"
                                    @onclick="() => PromptRevoke(session)">
                                Revoke
                            </button>
                        }
                        else
                        {
                            <span class="badge badge-current">Current</span>
                        }
                    </td>
                </tr>
            }
        </tbody>
    </table>

    @if (_sessionToRevoke is not null)
    {
        <div class="modal-overlay">
            <div class="modal-dialog">
                <h4>Revoke Session</h4>
                <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> from <strong>@_sessionToRevoke.Location</strong>?</p>
                <div class="modal-actions">
                    <button class="btn btn-danger" @onclick="ConfirmRevoke">Revoke</button>
                    <button class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = new();
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter] public EventCallback<string> OnSessionRevoked { get; set; }

    private ActiveSession? _sessionToRevoke;

    private void PromptRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is not null)
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            await OnSessionRevoked.InvokeAsync(_sessionToRevoke.Id);
            _sessionToRevoke = null;
        }
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
    }
}

