    {
        <ChangePasswordPanel />

        <div class="two-factor-section">
            <h3>Two-Factor Authentication</h3>
            <div class="two-factor-toggle">
                <label class="toggle-item">
                    <input type="checkbox" checked="@_twoFactorEnabled" disabled class="toggle-switch" />
                    <span>Two-Factor Authentication</span>
                    <span class="status-indicator @(_twoFactorEnabled ? "status-active" : "status-inactive")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </label>
            </div>

