@namespace sv_727400e45d114820a815880ed7ca91b9.Components.Settings

<div class="appearance-preview @_themeClass @_fontClass @(_compactMode ? "compact" : "")">
    <div class="preview-header">Live Preview</div>
    <div class="preview-content">
        <p class="preview-title">Sample Heading</p>
        <p class="preview-text">This is how your content will appear with the selected settings. The theme is <strong>@Theme</strong>, font size is <strong>@FontSize</strong>, and language is <strong>@Language</strong>.</p>
        <div class="preview-buttons">
            <span class="preview-btn primary">Primary Button</span>
            <span class="preview-btn secondary">Secondary Button</span>
        </div>
    </div>
</div>

@code {
    [Parameter] public string Theme { get; set; } = "Light";
    [Parameter] public string FontSize { get; set; } = "Medium";
    [Parameter] public string Language { get; set; } = "English";
    [Parameter] public bool CompactMode { get; set; }

    private string _themeClass => Theme.ToLowerInvariant() switch
    {
        "dark" => "preview-dark",
        "system" => "preview-system",
        _ => "preview-light"
    };

    private string _fontClass => FontSize.ToLowerInvariant() switch
    {
        "small" => "preview-font-small",
        "large" => "preview-font-large",
        _ => "preview-font-medium"
    };

    private bool _compactMode => CompactMode;
}

@namespace sv_727400e45d114820a815880ed7ca91b9.Components.Settings
@using sv_727400e45d114820a815880ed7ca91b9.Models
@inject ISettingsService SettingsService

<div class="settings-section">
    <h2>Appearance Settings</h2>

    @if (_loading)
    {
        <p>Loading appearance settings...</p>
    }
    else
    {
        <div class="appearance-form">
            <div class="form-group">
                <label>Theme</label>
                <div class="radio-group">
                    @foreach (var theme in _themes)
                    {
                        <label class="radio-item">
                            <input type="radio" name="theme" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <span>@theme</span>
                        </label>
                    }
                </div>
            </div>

            <div class="form-group">
                <label>Font Size</label>
                <div class="radio-group">
                    @foreach (var size in _fontSizes)
                    {
                        <label class="radio-item">
                            <input type="radio" name="fontSize" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <span>@size</span>
                        </label>
                    }
                </div>
            </div>

            <div class="form-group">
                <label for="language">Language</label>
                <select id="language" @bind="_language" class="form-control">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <div class="form-group">
                <label class="toggle-item">
                    <input type="checkbox" @bind="_compactMode" class="toggle-switch" />
                    <span>Compact Mode</span>
                </label>
            </div>

            <AppearancePreview Theme="@_theme" FontSize="@_fontSize"
                               Language="@_language" CompactMode="@_compactMode" />

            <div class="form-actions">
                <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
            </div>

            @if (_showSuccess)
            {
                <div class="toast toast-success">Appearance settings saved!</div>
            }
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _showSuccess;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _showSuccess = true;
        _ = HideSuccessAfterDelay();
    }

    private async Task HideSuccessAfterDelay()
    {
        await Task.Delay(3000);
        _showSuccess = false;
        await InvokeAsync(StateHasChanged);
    }
}

