namespace sv_727400e45d114820a815880ed7ca91b9.Models;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);
public record NotificationPrefs(bool EmailNotifications, bool PushNotifications, bool WeeklyDigest, List<string> MutedChannels);
public record SecuritySettings(bool TwoFactorEnabled, DateTime? LastPasswordChange, List<ActiveSession> Sessions);
public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);
public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@page "/settings"
@rendermode InteractiveServer

@using sv_727400e45d114820a815880ed7ca91b9.Components.Settings

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="SetActiveSection" />

    <main class="settings-content">
        @switch (_activeSection)
        {
            case "profile":
                <ProfileSection />
                break;
            case "notifications":
                <NotificationsSection />
                break;
            case "security":
                <SecuritySection />
                break;
            case "appearance":
                <AppearanceSection />
                break;
        }
    </main>
</div>

@code {
    private string _activeSection = "profile";

    private void SetActiveSection(string section)
    {
        _activeSection = section;
    }
}

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 4rem);
    gap: 0;
}

/* Sidebar */
.settings-sidebar {
    width: 240px;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding: 1rem 0;
    flex-shrink: 0;
}

.settings-nav {
    list-style: none;
    padding: 0;
    margin: 0;
}

.settings-nav-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.5rem;
    cursor: pointer;
    transition: background-color 0.2s, border-left-color 0.2s;
    border-left: 3px solid transparent;
    color: #495057;
}

.settings-nav-item:hover {
    background: #e9ecef;
}

.settings-nav-item.active {
    background: #e7f1ff;
    border-left-color: #0d6efd;
    color: #0d6efd;
    font-weight: 600;
}

.settings-nav-icon {
    font-size: 1.2rem;
}

/* Main content */
.settings-content {
    flex: 1;
    padding: 2rem;
    max-width: 800px;
}

.settings-section h2 {
    margin-bottom: 1.5rem;
    font-size: 1.5rem;
    color: #212529;
    border-bottom: 1px solid #dee2e6;
    padding-bottom: 0.75rem;
}

/* Form elements */
.form-group {
    margin-bottom: 1.25rem;
}

.form-group label {
    display: block;
    margin-bottom: 0.4rem;
    font-weight: 500;
    color: #495057;
}

.form-control {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ced4da;
    border-radius: 0.375rem;
    font-size: 1rem;
    transition: border-color 0.2s;
    box-sizing: border-box;
}

.form-control:focus {
    outline: none;
    border-color: #86b7fe;
    box-shadow: 0 0 0 0.2rem rgba(13, 110, 253, 0.25);
}

/* Buttons */
.form-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
}

.btn {
    padding: 0.5rem 1.25rem;
    border: none;
    border-radius: 0.375rem;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background-color 0.2s;
}

.btn-primary {
    background: #0d6efd;
    color: white;
}

.btn-primary:hover {
    background: #0b5ed7;
}

.btn-secondary {
    background: #6c757d;
    color: white;
}

.btn-secondary:hover {
    background: #5c636a;
}

.btn-danger {
    background: #dc3545;
    color: white;
}

.btn-danger:hover {
    background: #bb2d3b;
}

.btn-sm {
    padding: 0.25rem 0.75rem;
    font-size: 0.85rem;
}

/* Toast messages */
.toast {
    margin-top: 1rem;
    padding: 0.75rem 1rem;
    border-radius: 0.375rem;
    font-weight: 500;
}

.toast-success {
    background: #d1e7dd;
    color: #0f5132;
    border: 1px solid #badbcc;
}

.toast-error {
    background: #f8d7da;
    color: #842029;
    border: 1px solid #f5c2c7;
}

/* Avatar */
.avatar-preview {
    margin-bottom: 1.5rem;
    text-align: center;
}

.avatar-image {
    width: 100px;
    height: 100px;
    border-radius: 50%;
    object-fit: cover;
    border: 3px solid #dee2e6;
    margin-bottom: 0.5rem;
    display: block;
    margin-left: auto;
    margin-right: auto;
}

.avatar-url-display {
    font-size: 0.8rem;
    color: #6c757d;
    word-break: break-all;
}

/* Toggle items */
.toggle-group {
    display: flex;
    flex-direction: column;
    gap: 1rem;
    margin-bottom: 1.5rem;
}

.toggle-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    cursor: pointer;
}

.toggle-switch {
    width: 1.25rem;
    height: 1.25rem;
    cursor: pointer;
}

/* Channels */
.channels-section {
    margin-bottom: 1.5rem;
}

.channels-section h3 {
    margin-bottom: 0.75rem;
    font-size: 1.1rem;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.5rem;
    padding: 0.4rem 0;
    cursor: pointer;
}

/* Expandable panel */
.expandable-panel {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    margin-bottom: 1.5rem;
    overflow: hidden;
}

.panel-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    width: 100%;
    padding: 1rem 1.25rem;
    background: #f8f9fa;
    border: none;
    cursor: pointer;
    font-size: 1rem;
    font-weight: 500;
}

.panel-header:hover {
    background: #e9ecef;
}

.panel-body {
    padding: 1.25rem;
    border-top: 1px solid #dee2e6;
}

/* Two-factor */
.two-factor-section {
    margin-bottom: 1.5rem;
}

.two-factor-section h3 {
    margin-bottom: 0.75rem;
    font-size: 1.1rem;
}

.status-indicator {
    margin-left: 0.75rem;
    padding: 0.2rem 0.6rem;
    border-radius: 1rem;
    font-size: 0.8rem;
    font-weight: 600;
}

.status-active {
    background: #d1e7dd;
    color: #0f5132;
}

.status-inactive {
    background: #f8d7da;
    color: #842029;
}

.last-password-change {
    font-size: 0.85rem;
    color: #6c757d;
    margin-top: 0.5rem;
}

/* Sessions table */
.sessions-section h3 {
    margin-bottom: 0.75rem;
    font-size: 1.1rem;
}

.sessions-table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 1rem;
}

.sessions-table th,
.sessions-table td {
    padding: 0.75rem;
    text-align: left;
    border-bottom: 1px solid #dee2e6;
}

.sessions-table th {
    background: #f8f9fa;
    font-weight: 600;
    font-size: 0.85rem;
    text-transform: uppercase;
    color: #6c757d;
}

.badge-current {
    background: #cff4fc;
    color: #055160;
    padding: 0.2rem 0.6rem;
    border-radius: 1rem;
    font-size: 0.8rem;
    font-weight: 600;
}

/* Modal */
.modal-overlay {
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: rgba(0, 0, 0, 0.5);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
}

.modal-dialog {
    background: white;
    border-radius: 0.5rem;
    padding: 1.5rem;
    max-width: 400px;
    width: 90%;
    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);
}

.modal-dialog h4 {
    margin-bottom: 0.75rem;
}

.modal-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.25rem;
    justify-content: flex-end;
}

/* Radio groups */
.radio-group {
    display: flex;
    gap: 1.5rem;
}

.radio-item {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    cursor: pointer;
}

/* Appearance Preview */
.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    margin: 1.5rem 0;
    overflow: hidden;
}

.preview-header {
    padding: 0.5rem 1rem;
    background: #f8f9fa;
    font-weight: 600;
    font-size: 0.85rem;
    text-transform: uppercase;
    color: #6c757d;
    border-bottom: 1px solid #dee2e6;
}

.preview-content {
    padding: 1.25rem;
}

.preview-title {
    font-weight: 600;
    font-size: 1.1rem;
    margin-bottom: 0.5rem;
}

.preview-text {
    color: #495057;
    margin-bottom: 1rem;
    line-height: 1.5;
}

.preview-buttons {
    display: flex;
    gap: 0.75rem;
}

.preview-btn {
    padding: 0.4rem 1rem;
    border-radius: 0.375rem;
    font-size: 0.85rem;
}

.preview-btn.primary {
    background: #0d6efd;
    color: white;
}

.preview-btn.secondary {
    background: #6c757d;
    color: white;
}

/* Theme preview variants */
.preview-dark {
    background: #212529;
    color: #f8f9fa;
}

.preview-dark .preview-header {
    background: #2c3034;
    color: #adb5bd;
    border-bottom-color: #495057;
}

.preview-dark .preview-text {
    color: #ced4da;
}

.preview-system {
    background: #f0f4f8;
}

/* Font size preview variants */
.preview-font-small .preview-content {
    font-size: 0.85rem;
}

.preview-font-medium .preview-content {
    font-size: 1rem;
}

.preview-font-large .preview-content {
    font-size: 1.15rem;
}

/* Compact mode */
.appearance-preview.compact .preview-content {
    padding: 0.75rem;
    line-height: 1.3;
}

.appearance-preview.compact .preview-content p {
    margin-bottom: 0.5rem;
}

namespace sv_727400e45d114820a815880ed7ca91b9.Models;

