+    background: #5c636a;
+}
+
+.btn-danger {
+    background: #dc3545;
+    color: white;
+}
+
+.btn-danger:hover {
+    background: #bb2d3b;
+}
+
+.btn-sm {
+    padding: 0.25rem 0.75rem;
+    font-size: 0.85rem;
+}
+
+/* Toast messages */
+.toast {
+    margin-top: 1rem;
+    padding: 0.75rem 1rem;
+    border-radius: 0.375rem;
+    font-weight: 500;
+}
+
+.toast-success {
+    background: #d1e7dd;
+    color: #0f5132;
+    border: 1px solid #badbcc;
+}
+
+.toast-error {
+    background: #f8d7da;
+    color: #842029;
+    border: 1px solid #f5c2c7;
+}
+
+/* Avatar */
+.avatar-preview {
+    margin-bottom: 1.5rem;
+    text-align: center;
+}
+
+.avatar-image {
+    width: 100px;
+    height: 100px;
+    border-radius: 50%;
+    object-fit: cover;
+    border: 3px solid #dee2e6;
+    margin-bottom: 0.5rem;
+    display: block;
+    margin-left: auto;
+    margin-right: auto;
+}
+
+.avatar-url-display {
+    font-size: 0.8rem;
+    color: #6c757d;
+    word-break: break-all;
+}
+
+/* Toggle items */
+.toggle-group {
+    display: flex;
+    flex-direction: column;
+    gap: 1rem;
+    margin-bottom: 1.5rem;
+}
+
+.toggle-item {
+    display: flex;
+    align-items: center;
+    gap: 0.75rem;
+    cursor: pointer;
+}
+
+.toggle-switch {
+    width: 1.25rem;
+    height: 1.25rem;
+    cursor: pointer;
+}
+
+/* Channels */
+.channels-section {
+    margin-bottom: 1.5rem;
+}
+
+.channels-section h3 {
+    margin-bottom: 0.75rem;
+    font-size: 1.1rem;
+}
+
+.channel-item {
+    display: flex;
+    align-items: center;
+    gap: 0.5rem;
+    padding: 0.4rem 0;
+    cursor: pointer;
+}
+
+/* Expandable panel */
+.expandable-panel {
+    border: 1px solid #dee2e6;
+    border-radius: 0.5rem;
+    margin-bottom: 1.5rem;
+    overflow: hidden;
+}
+
+.panel-header {
+    display: flex;
+    justify-content: space-between;
+    align-items: center;
+    width: 100%;
+    padding: 1rem 1.25rem;
+    background: #f8f9fa;
+    border: none;
+    cursor: pointer;
+    font-size: 1rem;
+    font-weight: 500;
+}
+
+.panel-header:hover {
+    background: #e9ecef;
+}
+
+.panel-body {
+    padding: 1.25rem;
+    border-top: 1px solid #dee2e6;
+}
+
+/* Two-factor */
+.two-factor-section {
+    margin-bottom: 1.5rem;
+}
+
+.two-factor-section h3 {
+    margin-bottom: 0.75rem;
+    font-size: 1.1rem;
+}
+
+.status-indicator {
+    margin-left: 0.75rem;
+    padding: 0.2rem 0.6rem;
+    border-radius: 1rem;
+    font-size: 0.8rem;
+    font-weight: 600;
+}
+
+.status-active {
+    background: #d1e7dd;
+    color: #0f5132;
+}
+
+.status-inactive {
+    background: #f8d7da;
+    color: #842029;
+}
+
+.last-password-change {
+    font-size: 0.85rem;
+    color: #6c757d;
+    margin-top: 0.5rem;
+}
+
+/* Sessions table */
+.sessions-section h3 {
+    margin-bottom: 0.75rem;
+    font-size: 1.1rem;
+}
+
+.sessions-table {
+    width: 100%;
+    border-collapse: collapse;
+    margin-bottom: 1rem;
+}
+
+.sessions-table th,
+.sessions-table td {
+    padding: 0.75rem;
+    text-align: left;
+    border-bottom: 1px solid #dee2e6;
+}
+
+.sessions-table th {
+    background: #f8f9fa;
+    font-weight: 600;
+    font-size: 0.85rem;
+    text-transform: uppercase;
+    color: #6c757d;
+}
+
+.badge-current {
+    background: #cff4fc;
+    color: #055160;
+    padding: 0.2rem 0.6rem;
+    border-radius: 1rem;
+    font-size: 0.8rem;
+    font-weight: 600;
+}
+
+/* Modal */
+.modal-overlay {
+    position: fixed;
+    top: 0;
+    left: 0;
+    right: 0;
+    bottom: 0;
+    background: rgba(0, 0, 0, 0.5);
+    display: flex;
+    align-items: center;
+    justify-content: center;
+    z-index: 1000;
+}
+
+.modal-dialog {
+    background: white;
+    border-radius: 0.5rem;
+    padding: 1.5rem;
+    max-width: 400px;
+    width: 90%;
+    box-shadow: 0 10px 30px rgba(0, 0, 0, 0.2);
+}
+
+.modal-dialog h4 {
+    margin-bottom: 0.75rem;
+}
+
+.modal-actions {
+    display: flex;
+    gap: 0.75rem;
+    margin-top: 1.25rem;
+    justify-content: flex-end;
+}
+
+/* Radio groups */
+.radio-group {
+    display: flex;
+    gap: 1.5rem;
+}
+
+.radio-item {
+    display: flex;
+    align-items: center;
+    gap: 0.4rem;
+    cursor: pointer;
+}
+
+/* Appearance Preview */
+.appearance-preview {
+    border: 1px solid #dee2e6;
+    border-radius: 0.5rem;
+    margin: 1.5rem 0;
+    overflow: hidden;
+}
+
+.preview-header {
+    padding: 0.5rem 1rem;
+    background: #f8f9fa;
+    font-weight: 600;
+    font-size: 0.85rem;
+    text-transform: uppercase;
+    color: #6c757d;
+    border-bottom: 1px solid #dee2e6;
+}
+
+.preview-content {
+    padding: 1.25rem;
+}
+
+.preview-title {
+    font-weight: 600;
+    font-size: 1.1rem;
+    margin-bottom: 0.5rem;
+}
+
+.preview-text {
+    color: #495057;
+    margin-bottom: 1rem;
+    line-height: 1.5;
+}
+
+.preview-buttons {
+    display: flex;
+    gap: 0.75rem;
+}
+
+.preview-btn {
+    padding: 0.4rem 1rem;
+    border-radius: 0.375rem;
+    font-size: 0.85rem;
+}
+
+.preview-btn.primary {
+    background: #0d6efd;
+    color: white;
+}
+
+.preview-btn.secondary {
+    background: #6c757d;
+    color: white;
+}
+
+/* Theme preview variants */
+.preview-dark {
+    background: #212529;
+    color: #f8f9fa;
+}
+
+.preview-dark .preview-header {
+    background: #2c3034;
+    color: #adb5bd;
+    border-bottom-color: #495057;
+}
+
+.preview-dark .preview-text {
+    color: #ced4da;
+}
+
+.preview-system {
+    background: #f0f4f8;
+}
+
+/* Font size preview variants */
+.preview-font-small .preview-content {
+    font-size: 0.85rem;
+}
+
+.preview-font-medium .preview-content {
+    font-size: 1rem;
+}
+
+.preview-font-large .preview-content {
+    font-size: 1.15rem;
+}
+
+/* Compact mode */
+.appearance-preview.compact .preview-content {
+    padding: 0.75rem;
+    line-height: 1.3;
+}
+
+.appearance-preview.compact .preview-content p {
+    margin-bottom: 0.5rem;
+}
